"use client";

import type { VariantProps } from "cva";
import { Keyboard as RACKeyboard } from "react-aria-components";
import { KeyboardStyles } from "./styles";

export interface KeyboardProps
  extends React.ComponentProps<typeof RACKeyboard>,
    VariantProps<typeof KeyboardStyles> {}

export function Keyboard({ className, variant, ...props }: KeyboardProps) {
  return (
    <RACKeyboard
      {...props}
      className={KeyboardStyles({ className, variant })}
      data-slot="keyboard"
    />
  );
}

import { cva } from "~/registry/lib/cva";

export const KeyboardStyles = cva({
  defaultVariants: {
    variant: "default",
  },
  variants: {
    variant: {
      default:
        "pointer-events-none inline-flex h-5 select-none items-center gap-1 rounded border bg-muted px-1.5 font-medium font-mono text-[10px] text-muted-foreground",
      menu: "ml-auto text-muted-foreground text-xs tracking-widest",
    },
  },
});
